let res=[];
for(let i=0;i<T;i++){
  const [brand,model]=lines[idx++].trim().split(' ');
  const year=parseInt(lines[idx++].trim(),10);
  res.push(`You dream of owning a ${brand} ${model} in the year ${year}.`);
}
console.log(res.join('\n'));

